#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=350005;
struct node
{
	ll suma,sumb,laz;
} tr[N<<2];
ll n,m,a[N],b[N];
set<int> st;
void push_down(int l,int r,int u)
{
	if(!tr[u].laz) return;
	int mid=(l+r)/2;
	int ls=u*2,rs=u*2+1;
	tr[ls].sumb+=(mid-l+1)*tr[u].laz;
	tr[rs].sumb+=(r-mid)*tr[u].laz;
	tr[ls].laz+=tr[u].laz,tr[rs].laz+=tr[u].laz;
	tr[u].laz=0;
}
void push_up(int u)
{
	int ls=u*2,rs=u*2+1;
	tr[u].suma=tr[ls].suma+tr[rs].suma;
	tr[u].sumb=tr[ls].sumb+tr[rs].sumb;
}
void build(int l,int r,int u)
{
	if(l==r)
	{
		tr[u].suma=a[l];
		tr[u].sumb=b[l];
		return;
	}
	int ls=u*2,rs=u*2+1;
	int mid=(l+r)/2;
	build(l,mid,ls);
	build(mid+1,r,rs);
	push_up(u);
}
void update1(int l,int r,int u,int num,ll val)
{
	if(l==r&&l==num)
	{
		tr[u].suma+=val;
		return;
	}
	int ls=u*2,rs=u*2+1;
	int mid=(l+r)/2;
	if(num<=mid) update1(l,mid,ls,num,val);
	if(num>mid) update1(mid+1,r,rs,num,val);
	push_up(u);
}
ll query_a(int l,int r,int L,int R,int u)
{
	if(l<=L&&R<=r) return tr[u].suma;
	ll mid=(L+R)/2,sum=0;
	int ls=u*2,rs=u*2+1;
	if(l<=mid) sum+=query_a(l,r,L,mid,ls);
	if(r>mid) sum+=query_a(l,r,mid+1,R,rs);
	return sum;
}
void update2(int l,int r,int L,int R,int u,ll val)
{
	if(l<=L&&R<=r)
	{
		tr[u].sumb+=((R-L+1)*val);
		tr[u].laz+=val;
		return;
	}
	push_down(L,R,u);
	int mid=(L+R)/2;
	int ls=u*2,rs=u*2+1;
	if(l<=mid) update2(l,r,L,mid,ls,val);
	if(r>mid) update2(l,r,mid+1,R,rs,val);
	push_up(u);
}
ll query_b(ll num,int l,int r,int u)
{
	if(l==r&&l==num) return tr[u].sumb;
	push_down(l,r,u);
	int mid=(l+r)/2;
	int ls=u*2,rs=u*2+1;
	if(num<=mid) return query_b(num,l,mid,ls);
	if(num>mid) return query_b(num,mid+1,r,rs);
	return -1;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	for(int i=1;i<=n;i++)
	{
		cin>>b[i];
	}
	for(int i=1;i<=n;i++)
	{
		if(a[i]>b[i]) st.insert(i);
	}
	build(1,n,1);
	while(m--)
	{
		ll op,l,r,val,add;
		cin>>op;
		if(op==1)
		{
			cin>>add>>val;
			update1(1,n,1,add,val);
			st.insert(add);
		}
		if(op==2)
		{
			cin>>l>>r;
			cout<<query_a(l,r,1,n,1)<<'\n';
		}
		if(op==3)
		{
			cin>>l>>r>>val;
			update2(l,r,1,n,1,val);
		}
		if(op==4)
		{
			cin>>add;
			cout<<query_b(add,1,n,1)<<'\n';
		}
		if(op==5)
		{
			cin>>l>>r;
			auto it=st.lower_bound(l);
			while(it!=st.end())
			{
				int num=*it;
				if(num>r) break;
				ll fa=query_a(num,num,1,n,1),fb=query_b(num,1,n,1);
				if(fa>fb) update1(1,n,1,num,fb-fa);
				st.erase(num);
				it=st.lower_bound(l);
			}
		}
		if(op==6)
		{
			cin>>l>>r;
			auto it=st.lower_bound(l);
			while(it!=st.end())
			{
				int num=*it;
				if(num>r) break;
				ll fa=query_a(num,num,1,n,1),fb=query_b(num,1,n,1);
				if(fa>fb) update2(num,num,1,n,1,fa-fb);
				st.erase(num);
				it=st.lower_bound(l);
			}
		}
	}
	return 0;
}
